function generateCacheKey(url, customKey, request) {
  const baseUrl = url.origin + url.pathname + url.search;
  
  if (customKey) {
    return new Request(`${baseUrl}?__cache_key=${customKey}`, {
      method: request.method,
      headers: request.headers
    });
  }
  
  const varyHeaders = ['Accept', 'Accept-Encoding', 'Accept-Language'];
  const keyParts = [baseUrl];
  
  for (const header of varyHeaders) {
    const value = request.headers.get(header);
    if (value) {
      keyParts.push(`${header}:${value}`);
    }
  }
  
  return new Request(keyParts.join('|'), {
    method: request.method
  });
}

function sanitizeCacheKey(key) {
  if (!key || typeof key !== 'string') {
    return '';
  }
  
  key = key.substring(0, 256);
  key = key.replace(/[^a-zA-Z0-9_\-:.]/g, '');
  
  return key;
}

function sanitizeHeaders(headers) {
  const sanitized = new Headers();
  const allowedHeaders = [
    'accept',
    'accept-encoding',
    'accept-language',
    'authorization',
    'content-type',
    'user-agent'
  ];
  
  const dangerousHeaders = [
    'x-forwarded-for',
    'x-real-ip',
    'x-forwarded-host',
    'x-forwarded-proto'
  ];
  
  for (const [key, value] of headers.entries()) {
    const lowerKey = key.toLowerCase();
    
    if (dangerousHeaders.includes(lowerKey)) {
      continue;
    }
    
    if (allowedHeaders.includes(lowerKey)) {
      sanitized.set(key, value);
    }
  }
  
  return sanitized;
}

function isValidAuthToken(authHeader) {
  if (!authHeader.startsWith('Bearer ')) {
    return false;
  }
  
  const token = authHeader.substring(7);
  
  if (token.length < 32 || token.length > 512) {
    return false;
  }
  
  if (!/^[a-zA-Z0-9_\-\.]+$/.test(token)) {
    return false;
  }
  
  const validTokens = [
    'your_valid_token_here_replace_with_actual_validation',
    'another_valid_token'
  ];
  
  return validTokens.includes(token);
}